  ('immigration-1aab856d-moex-00131', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '某建商欲取得獎勵樓地板面積之許可，遂向地方政府依土地使用分區自治條例申請設立公共 開放空間，地方政府作成授益處分時，要求建商須簽署開放空間之切結書，依實務見解該切 結書之法律性質為下列何者？', '["行政契約之履行條款", "行政處分之準負擔附款", "行政處分之條件", "行政契約之生效條款"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7185f513df9b", "answer_pdf_sha1": "13755252dfea", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00132', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '有關行政契約之敘述，下列何者正確？', '["行政契約性質上係屬公權力行政", "行政契約僅限雙務契約", "行政契約亦受契約自由之保障，與私法契約同", "行政契約之締結僅限於行政機關與人民之間"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7185f513df9b", "answer_pdf_sha1": "13755252dfea", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00133', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '衛生主管機關對於某商家所販售之食品，公開警告指稱該食品含有有害人體健康之添加物， 經查並無此事。下列何者非屬該商家所得提出之權利或救濟途徑？', '["提起一般給付訴訟", "享有結果除去請求權", "享有損害賠償請求權或補償請求權", "提起撤銷之訴"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7185f513df9b", "answer_pdf_sha1": "13755252dfea", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00134', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '依司法實務見解，下列何者違反一行為不二罰原則？', '["貨物進口人填具一張進口報單逃漏進口稅、貨物稅及營業稅，依各該稅法之規定併合處罰", "非藥商於一定期間多次重複地利用傳播方法，宣傳醫療效能，以達招徠銷售為目的之行為， 主管機關按刊播之次數予以裁罰", "稽徵機關依稅法規定將逾期繳納稅捐者，每逾2日按滯納數額加徵百分之一之滯納金", "主管機關對於違停紅線之汽車駕駛人，每逾2小時連續舉發之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7185f513df9b", "answer_pdf_sha1": "13755252dfea", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00135', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '下列何者係屬具行政處分性質之執行命令？', '["罰鍰處分", "限制住居處分", "確認違章建築處分", "核課處分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7185f513df9b", "answer_pdf_sha1": "13755252dfea", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00136', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '關於政府資訊公開之敘述，下列何者正確？', '["外國人得否申請提供政府資訊，須按照平等互惠之原則判斷", "外交部對國人所為之旅遊警示屬於政府資訊公開法列舉之應主動公開之政府資訊", "政府機關核准提供政府資訊之申請時，應給予重製或複製品，不得僅供閱覽", "人民向政府申請提供政府資訊時，依行政程序法之一般性規定應於2個月內為准駁之決定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7185f513df9b", "answer_pdf_sha1": "13755252dfea", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00137', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '甲向主管機關請求五項政府資訊，主管機關未在法定期間為准駁決定，甲循序提起訴願後， 該機關於訴願審議期間向甲提供其中三項政府資訊，其餘兩項拒絕提供，訴願審議機關應如 何處理甲之訴願？', '["甲之訴願不符訴願提起之要件，應不受理", "甲之訴願無理由，應予以駁回", "應就拒絕提供部分續行審議", "應命甲修正訴願書以認定訴願審議範圍"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7185f513df9b", "answer_pdf_sha1": "13755252dfea", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00138', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '依訴願法規定，關於提起訴願之期間，下列敘述何者正確？', '["期間之計算，除法律另有規定外，依行政訴訟法之規定", "在途期間之扣除，除法律另有規定外，依行政訴訟法之規定", "利害關係人未知悉行政處分者，自行政處分達到或公告期滿後，已逾1年者，不得提起訴願", "訴願人因不應歸責於己之事由，致遲誤訴願期間已逾1年而不得回復原狀者，不得提起訴願"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7185f513df9b", "answer_pdf_sha1": "13755252dfea", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00139', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '甲縣政府以都市計畫法所定「為配合中央、直轄市或縣（市）興建之重大設施」為由，變更 都市計畫主要計畫案，經內政部核定後，由甲縣政府公告實施。人民若不服該變更，循序提 起行政訴訟時，應以何機關為被告？', '["甲縣政府之公告為行政處分，應以其為被告機關", "內政部之核定為行政處分，甲縣政府之公告僅為執行行為，故應以內政部為被告機關", "視該變更係為配合中央，抑或配合直轄市或縣（市）而定", "內政部之核定及甲縣政府之公告均屬行政處分，得以其為共同被告"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7185f513df9b", "answer_pdf_sha1": "13755252dfea", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL)
